      locals: { heading: "对当地人而言", steps: [{ number: "01", title: "验证您的居住地", description: "快速且隐私——无需存储敏感文件即可确认您住在该城市。水电账单或本地身份证即可。" }, { number: "02", title: "标注您喜爱的地方", description: "添加您真正热爱的地方——您的街区咖啡馆、视野最佳的公园、祖父母那一代就在那里的市场摊位。" }, { number: "03", title: "写下真实评价", description: "如实说：最佳菜品、最差访问时间、游客照片中看不到的东西。当地人是 NativeWay 上的真相讲述者。" }, { number: "04", title: "创建本地路线", description: "将您最爱的地点串联成一日行程。添加背景、历史和各站之间的旅途。打造一份您愿意送给朋友的指南。" }], note: "当地人获得声誉、认可，以及（即将推出的）来自感激旅行者的打赏。" },
